```python
def serialize_errors(errors):
    """Serialize Schematics 2.x Errors"""
    if isinstance(errors, dict):
        res = {}

        for k,v in errors.iteritems():
            if isinstance(v, basestring):
                res[k] = v
            elif isinstance(v, list):
                res[k] = [m.summary for m in v]
            elif isinstance(v, dict):
                res[k] = serialize_errors(v)
            else:
                res[k] = [m.summary for m in v.messages]

        return res

    else:
        return errors
```

